/**
 * Unified request for `WalletService::execute_send`.
 *
 * Collapses the Swift→Rust→Swift→Rust trampoline into a single call by
 * bundling derivation, payload building, and signing into one operation.
 * Swift passes the seed phrase or private key; Rust derives the signing key
 * material, builds the chain-specific payload, signs, and broadcasts.
 */
nonisolated public struct SendExecutionRequest {
    /**
     * Spectra chain ID matching `sign_and_send` routing (0 = BTC, 1 = ETH, …).
     */
    public var chainId: UInt32
    /**
     * Chain display name for derivation lookup ("Bitcoin", "Ethereum", …).
     */
    public var chainName: String
    /**
     * BIP-32/SLIP-10 derivation path (e.g. "m/84'/0'/0'/0/0").
     */
    public var derivationPath: String
    /**
     * Seed phrase for HD derivation (mutually exclusive with `private_key_hex`).
     */
    public var seedPhrase: String?
    /**
     * Raw private key hex for non-HD wallets (mutually exclusive with `seed_phrase`).
     */
    public var privateKeyHex: String?
    /**
     * Source/sender address.
     */
    public var fromAddress: String
    /**
     * Destination/recipient address.
     */
    public var toAddress: String
    /**
     * Human-scale amount (e.g. 0.5 BTC, 1.0 ETH).
     */
    public var amount: Double
    /**
     * Contract/mint address for token sends (ERC-20, SPL, TRC-20, NEP-141).
     */
    public var contractAddress: String?
    /**
     * Token decimals for raw-unit conversion.
     */
    public var tokenDecimals: UInt32?
    /**
     * BTC fee rate in sat/vB.
     */
    public var feeRateSvb: Double?
    /**
     * UTXO fee in satoshis (BCH, BSV, LTC, DOGE).
     */
    public var feeSat: UInt64?
    /**
     * Sui gas budget in SUI.
     */
    public var gasBudget: Double?
    /**
     * Cardano fee in ADA.
     */
    public var feeAmount: Double?
    /**
     * EVM overrides JSON fragment (nonce, custom gas fees).
     */
    public var evmOverridesFragment: String?
    /**
     * Monero priority level.
     */
    public var moneroPriority: UInt32?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    nonisolated public init(
        /**
         * Spectra chain ID matching `sign_and_send` routing (0 = BTC, 1 = ETH, …).
         */chainId: UInt32, 
        /**
         * Chain display name for derivation lookup ("Bitcoin", "Ethereum", …).
         */chainName: String, 
        /**
         * BIP-32/SLIP-10 derivation path (e.g. "m/84'/0'/0'/0/0").
         */derivationPath: String, 
        /**
         * Seed phrase for HD derivation (mutually exclusive with `private_key_hex`).
         */seedPhrase: String?, 
        /**
         * Raw private key hex for non-HD wallets (mutually exclusive with `seed_phrase`).
         */privateKeyHex: String?, 
        /**
         * Source/sender address.
         */fromAddress: String, 
        /**
         * Destination/recipient address.
         */toAddress: String, 
        /**
         * Human-scale amount (e.g. 0.5 BTC, 1.0 ETH).
         */amount: Double, 
        /**
         * Contract/mint address for token sends (ERC-20, SPL, TRC-20, NEP-141).
         */contractAddress: String?, 
        /**
         * Token decimals for raw-unit conversion.
         */tokenDecimals: UInt32?, 
        /**
         * BTC fee rate in sat/vB.
         */feeRateSvb: Double?, 
        /**
         * UTXO fee in satoshis (BCH, BSV, LTC, DOGE).
         */feeSat: UInt64?, 
        /**
         * Sui gas budget in SUI.
         */gasBudget: Double?, 
        /**
         * Cardano fee in ADA.
         */feeAmount: Double?, 
        /**
         * EVM overrides JSON fragment (nonce, custom gas fees).
         */evmOverridesFragment: String?, 
        /**
         * Monero priority level.
         */moneroPriority: UInt32?) {
        self.chainId = chainId
        self.chainName = chainName
        self.derivationPath = derivationPath
        self.seedPhrase = seedPhrase
        self.privateKeyHex = privateKeyHex
        self.fromAddress = fromAddress
        self.toAddress = toAddress
        self.amount = amount
        self.contractAddress = contractAddress
        self.tokenDecimals = tokenDecimals
        self.feeRateSvb = feeRateSvb
        self.feeSat = feeSat
        self.gasBudget = gasBudget
        self.feeAmount = feeAmount
        self.evmOverridesFragment = evmOverridesFragment
        self.moneroPriority = moneroPriority
    }
}

#if compiler(>=6)
nonisolated extension SendExecutionRequest: Sendable {}
#endif


nonisolated extension SendExecutionRequest: Equatable, Hashable {
    public static func ==(lhs: SendExecutionRequest, rhs: SendExecutionRequest) -> Bool {
        if lhs.chainId != rhs.chainId {
            return false
        }
        if lhs.chainName != rhs.chainName {
            return false
        }
        if lhs.derivationPath != rhs.derivationPath {
            return false
        }
        if lhs.seedPhrase != rhs.seedPhrase {
